function.arguments:
{"code": "import json

# Access the full NPM packages data
pkg_file = globals().get('var_functions.query_db:8') or locals().get('var_functions.query_db:8')
with open(pkg_file, 'r') as f:
    all_packages = json.load(f)

# Parse VersionInfo to get latest release versions
latest_versions = {}
for pkg in all_packages:
    try:
        version_info = json.loads(pkg['VersionInfo'].replace('\n', ' ').strip())
        if version_info.get('IsRelease', False):
            name = pkg['Name']
            ordinal = version_info.get('Ordinal', 0)
            if name not in latest_versions or ordinal > latest_versions[name]['Ordinal']:
                latest_versions[name] = {
                    'Name': name,
                    'Version': pkg['Version'],
                    'Ordinal': ordinal
                }
    except:
        continue

latest_packages = list(latest_versions.values())
print('__RESULT__:')
print(json.dumps({
    'total_npm_packages': len(all_packages),
    'latest_release_packages': len(latest_packages)
}))"}

