for m in project_mappings:
    if m['System'] == 'NPM':
        key = (m['Name'], m['Version'])
        proj_lookup[key] = m['ProjectName']

# Match packages with projects
matched_packages = []
for pkg in latest_packages:
    key = (pkg['Name'], pkg['Version'])
    if key in proj_lookup:
        matched_packages.append({
            'Name': pkg['Name'],
            'Version': pkg['Version'],
            'ProjectName': proj_lookup[key]
        })

print('__RESULT__:')
print(json.dumps({
    'total_latest_release_packages': len(latest_packages),
    'matched_with_projects': len(matched_packages),
    'sample_matches': matched_packages[:10]
}))"}

{"code": "import json
import re

# Load all NPM packages
f = globals()['var_functions.query_db:46']
with open(f, 'r') as file:
    all_npm_packages = json.load(file)

# Load project mappings
f2 = globals()['var_functions.query_db:44']
with open(f2, 'r') as file:
    project_mappings = json.load(file)

# Load project info
f3 = globals()['var_functions.query_db:36']
with open(f3, 'r') as file:
    project_info_raw = json.load(file)

# Step 1: Find latest release version per package
latest_versions = {}
for pkg in all_npm_packages:
    try:
        vi = json.loads(pkg['VersionInfo'].replace('\n', ' ').strip())
        if vi.get('IsRelease', False):
            name = pkg['Name']
            version = pkg['Version']
            ordinal = vi.get('Ordinal', 0)
            if name not in latest_versions or ordinal > latest_versions[name]['Ordinal']:
                latest_versions[name] = {'Name': name, 'Version': version, 'Ordinal': ordinal}
    except:
        continue

latest_packages = list(latest_versions.values())

# Step 2: Map packages to projects
proj_lookup = {}
for m in project_mappings:
    proj_lookup[(m['Name'], m['Version'])] = m['ProjectName']

matched = []
for pkg in latest_packages:
    key = (pkg['Name'], pkg['Version'])
    if key in proj_lookup:
        matched.append({
            'Name': pkg['Name'],
            'Version': pkg['Version'],
            'Project': proj_lookup[key]
        })

# Step 3: Extract stars from project info
proj_stars = {}
for info in project_info_raw:
    text = info['Project_Information']
    stars_match = re.search(r'(\d+(?:,\d+)*)\s+stars', text)
    if stars_match:
        stars = int(stars_match.group(1).replace(',', ''))
        proj_match = re.search(r'The project\s+([\w-]+/[\w-]+)', text)
        if proj_match:
            proj_stars[proj_match.group(1)] = stars

# Step 4: Add stars to matched packages
result = []
for m in matched:
    if m['Project'] in proj_stars:
        result.append({
            'PackageName': m['Name'],
            'Version': m['Version'],
            'Project': m['Project'],
            'Stars': proj_stars[m['Project']]
        })

# Step 5: Sort by stars and get top 5
top_5 = sorted(result, key=lambda x: x['Stars'], reverse=True)[:5]

out = {
    'total_packages': len(all_npm_packages),
    'latest_release': len(latest_packages),
    'matched_projects': len(matched),
    'with_star_data': len(result),
    'top_5': top_5
}

print('__RESULT__:')
print(json.dumps(out))"}

{"code": "import json
import re

# Load full datasets
pkg_file = globals().get('var_functions.query_db:46') or locals().get('var_functions.query_db:46')
mappings_file = globals().get('var_functions.query_db:44') or locals().get('var_functions.query_db:44')
proj_file = globals().get('var_functions.query_db:36') or locals().get('var_functions.query_db:36')

with open(pkg_file, 'r') as f:
    all_packages = json.load(f)

with open(mappings_file, 'r') as f:
    mappings = json.load(f)

with open(proj_file, 'r') as f:
    proj_info = json.load(f)

# Parse projects for stars
proj_stars = {}
for info in proj_info:
    text = info['Project_Information']
    stars_match = re.search(r'(\d+(?:,\d+)*) stars', text)
    if stars_match:
        stars = int(stars_match.group(1).replace(',', ''))
        proj_match = re.search(r'The project (\S+)', text)
        if proj_match:
            proj_stars[proj_match.group(1)] = stars

# Build lookups
latest_releases = {}
for pkg in all_packages:
    try:
        vi_text = pkg['VersionInfo']
        if '\"IsRelease\": true' in vi_text or '"IsRelease": true' in vi_text:
            ordinal_match = re.search(r'\"Ordinal\":\s*(\d+)', vi_text)
            if ordinal_match:
                ordinal = int(ordinal_match.group(1))
                name = pkg['Name']
                version = pkg['Version']
                key = (name, version)
                if name not in latest_releases or ordinal > latest_releases[name]['ordinal']:
                    latest_releases[name] = {'key': key, 'ordinal': ordinal}
    except:
        continue

project_lookup = {}
for m in mappings:
    project_lookup[(m['Name'], m['Version'])] = m['ProjectName']

# Match and rank
matched = []
for name, info in latest_releases.items():
    if info['key'] in project_lookup:
        project = project_lookup[info['key']]
        if project in proj_stars:
            matched.append({
                'PackageName': name,
                'Version': info['key'][1],
                'Project': project,
                'Stars': proj_stars[project]
            })

top5 = sorted(matched, key=lambda x: x['Stars'], reverse=True)[:5]

print('__RESULT__:')
print(json.dumps({
    'packages_with_latest': len(latest_releases),
    'matched_count': len(matched),
    'top5': top5
}))"}

