import re

# Load all data
pkg_file = globals().get('var_functions.query_db:46') or locals().get('var_functions.query_db:46')
mappings_file = globals().get('var_functions.query_db:44') or locals().get('var_functions.query_db:44')
proj_file = globals().get('var_functions.query_db:66') or locals().get('var_functions.query_db:66')

with open(pkg_file, 'r') as f:
    packages = json.load(f)

with open(mappings_file, 'r') as f:
    mappings = json.load(f)

with open(proj_file, 'r') as f:
    project_info = json.load(f)

# Build project stars lookup (expanded dataset)
proj_stars = {}
for info in project_info:
    text = info['Project_Information']
    stars_match = re.search(r'(\d+(?:,\d+)*)\s+stars', text)
    if stars_match:
        stars = int(stars_match.group(1).replace(',', ''))
        proj_match = re.search(r'The project\s+([\w-]+/[\w-]+)', text)
        if proj_match:
            proj_stars[proj_match.group(1)] = stars

# Build project lookup from mappings
project_lookup = {}
for m in mappings:
    if m['System'] == 'NPM':
        project_lookup[(m['Name'], m['Version'])] = m['ProjectName']

# Find latest release for each package
latest_releases = {}
processed = 0
for pkg in packages:
    processed += 1
    try:
        # Handle JSON parsing
        vi_text = pkg['VersionInfo']
        if '"IsRelease": true' in vi_text or '\"IsRelease\": true' in vi_text:
            # Extract ordinal
            ordinal_match = re.search(r'"Ordinal"\s*:\s*(\d+)', vi_text)
            if ordinal_match:
                ordinal = int(ordinal_match.group(1))
                name = pkg['Name']
                version = pkg['Version']

                if name not in latest_releases or ordinal > latest_releases[name]['ordinal']:
                    latest_releases[name] = {
                        'key': (name, version),
                        'ordinal': ordinal
                    }
    except:
        continue

# Match packages with projects and stars
matched_packages = []
for pkg_name, pkg_info in latest_releases.items():
    key = pkg_info['key']
    if key in project_lookup:
        project_name = project_lookup[key]
        if project_name in proj_stars:
            # Only include direct packages (no nested dependency notation)
            if '>' not in pkg_name:
                matched_packages.append({
                    'PackageName': pkg_name,
                    'Version': key[1],
                    'ProjectName': project_name,
                    'Stars': proj_stars[project_name]
                })

# Sort by stars and get top 5
top_5 = sorted(matched_packages, key=lambda x: x['Stars'], reverse=True)[:5]

result = {
    'total_npm_packages': len(packages),
    'latest_release_packages': len(latest_releases),
    'matched_with_projects': len([p for p in latest_releases.values() if p['key'] in project_lookup]),
    'packages_with_star_data': len(matched_packages),
    'top_5_most_popular': top_5
}

print('__RESULT__:')
print(json.dumps(result, indent=2))"}
